- Use `npm install next-auth` to install the latest version of NextAuth.js.
- Configure JWT in your `next-auth.config.ts`:
  ```typescript
  import NextAuth from "next-auth";
  import CredentialsProvider from "next-auth/providers/credentials";

  export default NextAuth({
    providers: [
      CredentialsProvider({
        // ... provider options
      }),
    ],
    session: {
      strategy: "jwt",
    },
    jwt: {
      secret: process.env.JWT_SECRET,
    },
  });
  ```
- Set `JWT_SECRET` in your environment variables for security.
- Use the `getToken` function to access JWT token in your Next.js pages or API routes:
  ```typescript
  import { getToken } from "next-auth/jwt";

  export default async function handler(req, res) {
    const token = await getToken({ req });
    if (token) {
      // Token is valid, proceed with the request
    } else {
      // Token is invalid or missing, redirect to login page
    }
  }
  ```
- For client-side authentication, use `useSession` hook from NextAuth.js:
  ```typescript
  import { useSession } from "next-auth/react";

  function MyComponent() {
    const { data: session, status } = useSession();

    if (status === "loading") return <p>Loading...</p>;
    if (!session) return <a href="/api/auth/signin">Sign in</a>;

    return (
      <>
        Signed in as {session.user.email} <br />
        <button onClick={() => signOut()}>Sign out</button>
      </>
    );
  }
  ```
- Ensure to handle token expiration and refresh logic appropriately.

- Use `next-auth.js` for authentication.
- Install via npm: `npm install next-auth@latest`.
- Configure in `pages/api/auth/[...nextauth].js`.
- Implement middleware for API routes:
  ```bash
  // pages/api/middleware.js
  import { NextResponse } from 'next/server';
  export function middleware(request) {
    const token = request.cookies.get('token');
    if (!token) return new NextResponse(null, { status: 401 });
    return NextResponse.next();
  }
  ```
- Use `getSession()` or `getToken()` in API routes:
  ```javascript
  // pages/api/protected.js
  import { getSession } from 'next-auth/react';

  export default async function handler(req, res) {
    const session = await getSession({ req });
    if (!session) return res.status(401).json({ message: 'Unauthorized' });
    res.json({ user: session.user });
  }
  ```
- Protect pages using `useSession`:
  ```javascript
  // pages/protected.js
  import { useSession } from 'next-auth/react';

  export default function ProtectedPage() {
    const { data: session, status } = useSession();
    if (status === "loading") return <p>Loading...</p>;
    if (!session) return <p>Access Denied</p>;
    return <div>Welcome {session.user.name}</div>;
  }
  ```
- Ensure Next.js version is up to date for security patches.
